import React from 'react';

interface Order {
  id: string;
  customerName: string;
  status: 'Pending' | 'Shipped' | 'Completed';
  total: number;
  date: string;
}

const OrderCard = ({ order, onUpdateStatus }: { order: Order; onUpdateStatus: (id: string, status: Order['status']) => void }) => {
  const handleStatusChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    onUpdateStatus(order.id, event.target.value as Order['status']);
  };

  return (
    <div className="bg-gray-800 border border-gray-700 rounded-2xl p-4 shadow-md transition hover:border-indigo-500">
      <div className="flex justify-between items-center mb-2">
        <h3 className="text-white font-medium">Order #{order.id}</h3>
        <span className="text-gray-400 text-sm">{order.date}</span>
      </div>
      <p className="text-gray-300 mb-2">Customer: {order.customerName}</p>
      <p className="text-gray-300 mb-2">Total: ${order.total.toFixed(2)}</p>
      <div className="flex items-center gap-2">
        <label className="text-gray-400 text-sm">Status:</label>
        <select
          value={order.status}
          onChange={handleStatusChange}
          className="bg-gray-700 text-white rounded-lg p-2 focus:outline-none focus:ring-2 focus:ring-indigo-500"
        >
          <option value="Pending">Pending</option>
          <option value="Shipped">Shipped</option>
          <option value="Completed">Completed</option>
        </select>
      </div>
    </div>
  );
};

export default OrderCard;

