import React from 'react';

interface User {
  id: string;
  name: string;
  email: string;
  role: 'Admin' | 'Manager' | 'Staff';
  lastActive: string;
}

const UserList = ({ users, onRoleChange }: { users: User[]; onRoleChange: (id: string, role: User['role']) => void }) => {
  return (
    <div className="bg-gray-900 p-6 rounded-xl shadow-md">
      <h2 className="text-2xl font-semibold text-white mb-4">User Management</h2>
      <table className="w-full text-left">
        <thead>
          <tr className="border-b border-gray-700">
            <th className="py-2 text-gray-400">Name</th>
            <th className="py-2 text-gray-400">Email</th>
            <th className="py-2 text-gray-400">Role</th>
            <th className="py-2 text-gray-400">Last Active</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            <tr key={user.id} className="border-b border-gray-800 hover:bg-gray-800">
              <td className="py-2 text-white">{user.name}</td>
              <td className="py-2 text-gray-300">{user.email}</td>
              <td className="py-2">
                <select
                  value={user.role}
                  onChange={(e) => onRoleChange(user.id, e.target.value as User['role'])}
                  className="bg-gray-700 text-white rounded-lg p-1 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  <option value="Admin">Admin</option>
                  <option value="Manager">Manager</option>
                  <option value="Staff">Staff</option>
                </select>
              </td>
              <td className="py-2 text-gray-300">{user.lastActive}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default UserList;
